def solve(grid):
    from collections import deque
    R, C = len(grid), len(grid[0])
    result = [row[:] for row in grid]
    seeds = set()
    for r in range(R):
        for c in range(C):
            v = grid[r][c]
            same = 0
            diff = 0
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = r+dr, c+dc
                if 0 <= nr < R and 0 <= nc < C:
                    if grid[nr][nc] == v: same += 1
                    else: diff += 1
            if diff > same: seeds.add((r, c))
    zero_seeds = {(r,c) for r,c in seeds if grid[r][c] == 0}
    one_seeds = {(r,c) for r,c in seeds if grid[r][c] == 1}
    THRESHOLD = 10
    def get_component(start, val):
        comp = []
        visited = {start}
        q = deque([start])
        while q:
            r, c = q.popleft()
            comp.append((r,c))
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = r+dr, c+dc
                if 0 <= nr < R and 0 <= nc < C and (nr,nc) not in visited and grid[nr][nc] == val:
                    visited.add((nr,nc))
                    q.append((nr,nc))
        return comp
    all_zero_anom_cells = set()
    processed = set()
    zero_groups = []
    for seed in zero_seeds:
        if seed in processed: continue
        comp = get_component(seed, 0)
        group = comp if len(comp) <= THRESHOLD else [seed]
        for cell in group:
            processed.add(cell)
            all_zero_anom_cells.add(cell)
        zero_groups.append(group)
    for group in zero_groups:
        group_set = set(group)
        border = set()
        for r, c in group:
            for dr in [-1, 0, 1]:
                for dc in [-1, 0, 1]:
                    if dr == 0 and dc == 0: continue
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < R and 0 <= nc < C and (nr, nc) not in group_set and (nr, nc) not in all_zero_anom_cells:
                        border.add((nr, nc))
        for r, c in border:
            result[r][c] = 7
    for seed in one_seeds:
        comp = get_component(seed, 1)
        if len(comp) <= THRESHOLD:
            for r, c in comp: result[r][c] = 0
        else:
            result[seed[0]][seed[1]] = 0
    return result

