def solve(grid):
    from collections import deque, Counter
    R, C = len(grid), len(grid[0])
    result = [row[:] for row in grid]
    color_counts = Counter()
    for r in range(R):
        for c in range(C):
            color_counts[grid[r][c]] += 1
    bg = color_counts.most_common(1)[0][0]
    non_bg = [(r,c) for r in range(R) for c in range(C) if grid[r][c] != bg]
    non_bg_set = set(non_bg)
    visited = set()
    clusters = []
    for cell in non_bg:
        if cell in visited: continue
        cluster = []
        q = deque([cell])
        visited.add(cell)
        while q:
            r, c = q.popleft()
            cluster.append((r, c))
            for dr in [-1, 0, 1]:
                for dc in [-1, 0, 1]:
                    if dr == 0 and dc == 0: continue
                    nr, nc = r+dr, c+dc
                    if (nr, nc) in non_bg_set and (nr, nc) not in visited:
                        visited.add((nr, nc))
                        q.append((nr, nc))
        clusters.append(cluster)
    for cluster in clusters:
        two_cells = [(r,c) for r,c in cluster if grid[r][c] == 2]
        shape_cells = [(r,c) for r,c in cluster if grid[r][c] != 2]
        if not two_cells or not shape_cells: continue
        two_cols = set(c for r,c in two_cells)
        two_rows = set(r for r,c in two_cells)
        if len(two_cells) == 1:
            pr, pc = two_cells[0]
            for r, c in shape_cells:
                nr, nc = 2*pr - r, 2*pc - c
                if 0 <= nr < R and 0 <= nc < C:
                    result[nr][nc] = grid[r][c]
        elif len(two_cols) == 1:
            col = two_cols.pop()
            for r, c in shape_cells:
                nc = 2*col - c
                if 0 <= nc < C:
                    result[r][nc] = grid[r][c]
        elif len(two_rows) == 1:
            row = two_rows.pop()
            for r, c in shape_cells:
                nr = 2*row - r
                if 0 <= nr < R:
                    result[nr][c] = grid[r][c]
    return result
